SELECT lp.model_number
FROM laser_products lp
WHERE EXISTS (SELECT 1 FROM testing_data td WHERE td.product_id = lp.product_id);

SELECT lp.model_number, lp.serial_number, lp.operation_mode
FROM laser_products lp
WHERE lp.cooling_type = 'actively cooled';

SELECT model_number 
FROM laser_products 
WHERE product_id IN (SELECT product_id FROM datasheets);

SELECT COUNT(*) AS number_of_products
FROM laser_products
WHERE manufacturer_id = 1;

SELECT heatsink_type
FROM heatsinks
WHERE thermal_resistance_k_w = (
    SELECT MIN(thermal_resistance_k_w)
    FROM heatsinks
);

SELECT product_id, model_number
FROM laser_products
WHERE product_id = 1234;

SELECT model_number 
FROM laser_products 
WHERE product_id = 0;

SELECT cooling_type, description
FROM cooling_methods
WHERE cooling_id = 0;

SELECT AVG(output_power_w) AS average_output_power
FROM laser_products
WHERE warranty_period_months > 12;

SELECT COUNT(product_id) AS total_products
FROM laser_products
WHERE operation_mode = 'QCW' AND cooling_type = 'actively cooled';

SELECT COUNT(product_id) AS num_products
FROM laser_products
WHERE cooling_type = 'actively cooled' AND operation_mode = 'Continuous Wave';

SELECT output_power_w
FROM laser_products
WHERE model_number = 'JOLD-60' AND warranty_period_months > 12;
